public void testFactory_fromCalendarFields_AD() throws Exception {
    GregorianCalendar cal = new GregorianCalendar(2023, 5, 15, 10, 30, 45);
    cal.set(Calendar.ERA, GregorianCalendar.AD);
    LocalDate expected = new LocalDate(2023, 6, 15);
    assertEquals(expected, LocalDate.fromCalendarFields(cal));
}

public void testFactory_fromCalendarFields_AD() throws Exception {
    GregorianCalendar cal = new GregorianCalendar(2023, 5, 15, 10, 30, 45);
    cal.set(Calendar.ERA, GregorianCalendar.AD);
    cal.set(Calendar.MILLISECOND, 123);
    LocalDateTime expected = new LocalDateTime(2023, 6, 15, 10, 30, 45, 123);
    assertEquals(expected, LocalDateTime.fromCalendarFields(cal));
}

public void testFactory_fromCalendarFields_beforeYearZero10() throws Exception {
    GregorianCalendar cal = new GregorianCalendar(10, 11, 25, 0, 0, 0);
    cal.set(Calendar.ERA, GregorianCalendar.BC);
    LocalDate expected = new LocalDate(-9, 12, 25);
    assertEquals(expected, LocalDate.fromCalendarFields(cal));
}

public void testFactory_fromCalendarFields_beforeYearZero10() throws Exception {
    GregorianCalendar cal = new GregorianCalendar(10, 11, 25, 23, 59, 59);
    cal.set(Calendar.ERA, GregorianCalendar.BC);
    cal.set(Calendar.MILLISECOND, 999);
    LocalDateTime expected = new LocalDateTime(-9, 12, 25, 23, 59, 59, 999);
    assertEquals(expected, LocalDateTime.fromCalendarFields(cal));
}
